SELECT difficulty_level, COUNT(*) AS number_of_climbs
FROM climbing_records
GROUP BY difficulty_level;

SELECT COUNT(*) 
FROM climbing_records 
WHERE rating >= 4;

SELECT range, MAX(elevation) AS highest_elevation
FROM mountains
WHERE range = 'Northwest U.S. Coast Ranges';

SELECT name, elevation
FROM mountains
ORDER BY elevation DESC;

SELECT MIN(rating) AS lowest_rating
FROM climbing_records
WHERE difficulty_level = (SELECT MAX(difficulty_level) FROM climbing_records);

SELECT SUM(rental_cost) AS total_rental_cost
FROM equipment_rentals
WHERE user_id = 0;

SELECT name
FROM mountains
WHERE prominence = (SELECT MAX(prominence) FROM mountains);
